struct SkenionFrame {
  resolution: vec2<f32>,
  time: f32,
  frame: u32,
  u_value: f32,
  u_value2: f32,
  _pad0: vec2<f32>,
  u_color: vec4<f32>,
}

@group(0) @binding(0)
var<uniform> skenion: SkenionFrame;

struct VertexOut {
  @builtin(position) position: vec4<f32>,
}

@vertex
fn vs_main(@builtin(vertex_index) vertex_index: u32) -> VertexOut {
  var positions = array<vec2<f32>, 3>(
    vec2<f32>(-1.0, -3.0),
    vec2<f32>(-1.0,  1.0),
    vec2<f32>( 3.0,  1.0)
  );

  var out: VertexOut;
  out.position = vec4<f32>(positions[vertex_index], 0.0, 1.0);
  return out;
}

@fragment
fn fs_main() -> @location(0) vec4<f32> {
  return vec4<f32>(skenion.u_value, skenion.u_value2, 1.0 - skenion.u_value, 1.0) * skenion.u_color;
}
